17	export function runScenario(scenario: unknown): unknown {
18	  const { steps } = scenario as Scenario;
19	  const item = steps[0].items[0];
20	  const cursedMultiplier = item.cursed ? CURSED_MULTIPLIER : 1;
21	  const highEnchantmentMultiplier =
22	    (item.enchantment ?? 0) >= 5 ? HIGH_ENCHANTMENT_MULTIPLIER : 1;
23	  const itemBase =
24	    BASE_PRICE[item.type] * cursedMultiplier * highEnchantmentMultiplier;
25	  const premium = Math.round(itemBase * FIRST_INSURANCE_MULTIPLIER) + ADMIN_FEE;
26	  return { results: [{ premium }] };
27	}
