function itemModifierMultiplier(item: Item): number {
  const cursed = item.cursed ? CURSED_MULTIPLIER : 1;
  const highEnchantment =
    (item.enchantment ?? 0) >= 5 ? HIGH_ENCHANTMENT_MULTIPLIER : 1;
  return cursed * highEnchantment;
}

export function runScenario(scenario: unknown): unknown {
  const { steps } = scenario as Scenario;
  const item = steps[0].items[0];
  const itemPrice = BASE_PRICE[item.type] * itemModifierMultiplier(item);
  const premium = Math.round(itemPrice * FIRST_INSURANCE_MULTIPLIER) + ADMIN_FEE;
  return { results: [{ premium }] };
}
